INSERT INTO `agency_faqs` (`id`, `bus_agency_id`, `question`, `answer`, `order`, `status`, `created_at`, `updated_at`) VALUES
(1, 2, 'What are your baggage policies?', 'Each passenger is allowed one carry-on bag (max 7kg) and one checked bag (max 23kg). Additional baggage can be purchased at the terminal or online during booking.', 1, 1, '2025-06-14 10:27:19', '2025-06-14 10:27:19'),
(2, 2, 'How can I modify or cancel my booking?', 'You can modify or cancel your booking through our website or mobile app up to 24 hours before departure. Cancellation fees may apply based on the timing of your cancellation.', 5, 1, '2025-06-14 10:27:39', '2025-06-14 10:29:03'),
(3, 2, 'What amenities are available on board?', 'Our buses are equipped with comfortable reclining seats, free WiFi, power outlets, air conditioning, and onboard restrooms. Some routes also offer refreshment services.', 4, 1, '2025-06-14 10:27:58', '2025-06-14 10:28:56'),
(4, 2, 'Do you offer special assistance for passengers with disabilities?', 'Yes, we provide special assistance for passengers with disabilities. Please contact our customer service at least 48 hours before your journey to arrange the necessary support.', 3, 1, '2025-06-14 10:28:13', '2025-06-14 10:28:48'),
(5, 2, 'What is your refund policy?', 'Refunds are processed within 5-7 business days. The amount refunded depends on the cancellation timing and fare type. Please refer to our terms and conditions for detailed information.', 2, 1, '2025-06-14 10:28:34', '2025-06-14 10:28:40');
