INSERT INTO `email_template` (`id`, `type`, `subject`, `message`, `send_to_admin`, `created_at`, `updated_at`) VALUES
(1, 'payment_receipt', 'Payment Receipt - {AppName}', '<div width=\"100%\" style=\"padding: 0px; font-family: arial; line-height: 28px; height: 100%; width: 100%;\">\r\n    <div style=\"max-width: 700px; margin: 30px; font-size: 14px; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\">\r\n        <span style=\"font-size: 14px;\">ď»ż</span><table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" style=\"color: rgb(81, 77, 106); background-color: rgb(255, 255, 255); width: 100%; margin-bottom: 20px;\">\r\n            <tbody>\r\n            <tr>\r\n                <td>\r\n                    \r\n                </td>\r\n            </tr>\r\n            </tbody>\r\n        </table>\r\n        <h3 style=\"color: rgb(81, 77, 106); background-color: rgb(255, 255, 255);\"><b>Payment Receipt </b></h3><p style=\"color: rgb(81, 77, 106); background-color: rgb(255, 255, 255);\"><span style=\"font-size: 14px;\">Hello Mr./Mrs {UserName}</span></p><u style=\"color: rgb(81, 77, 106); background-color: rgb(255, 255, 0);\"><b><span style=\"font-size: 18px;\">Details of your payment receipt:</span></b></u><br><p style=\"color: rgb(81, 77, 106); background-color: rgb(255, 255, 255);\"><b>Distance:</b> {Distance}</p><p style=\"color: rgb(81, 77, 106); background-color: rgb(255, 255, 255);\"><b>Duration:</b> {Duree}</p><p style=\"color: rgb(81, 77, 106); background-color: rgb(255, 255, 255);\"><b>Sub Total:</b> {Subtotal}</p><p style=\"color: rgb(81, 77, 106); background-color: rgb(255, 255, 255);\"><b>Discount:</b> {Discount}</p><p style=\"color: rgb(81, 77, 106); background-color: rgb(255, 255, 255);\"><b>Tax:</b> {Tax}</p><p style=\"color: rgb(81, 77, 106); background-color: rgb(255, 255, 255);\"><b>Driver Tip:</b> {Tip}</p><p style=\"color: rgb(81, 77, 106); background-color: rgb(255, 255, 255);\"><b>Total:</b> {Total}</p><p style=\"color: rgb(81, 77, 106); background-color: rgb(255, 255, 255);\"><b>Date:</b> {Date}</p><br><p style=\"\"><b style=\"\"><font color=\"#000000\" style=\"background-color: rgb(255, 255, 0);\">Regards {AppName}</font></b></p><table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" style=\"color: rgb(81, 77, 106); background-color: rgb(255, 255, 255); width: 100%;\">\r\n            <tbody>\r\n            <tr>\r\n                \r\n                \r\n                \r\n                \r\n                \r\n                \r\n                \r\n                \r\n                \r\n                \r\n                \r\n                \r\n                \r\n            </tr>\r\n            </tbody>\r\n        </table>\r\n    </div>\r\n</div>', 'false', '2023-08-03 04:09:00', '2024-12-18 15:13:50'),
(2, 'wallet_topup', 'Wallet Topup Confirmation', '<div><b><font color=\"#000000\" style=\"background-color: rgb(255, 255, 0);\">Dear {UserName},</font></b></div><div>We are writing to confirm that your wallet has been successfully topped up with {Amount} on {Date}.</div><div><br></div><div><b><font color=\"#000000\" style=\"background-color: rgb(255, 255, 0);\">Transaction Details:</font></b></div><div><b><font color=\"#000000\" style=\"background-color: rgb(255, 255, 0);\">Date: {Date}</font></b></div><div><b><font color=\"#000000\" style=\"background-color: rgb(255, 255, 0);\">Amount: {Amount}</font></b></div><div><b><font color=\"#000000\" style=\"background-color: rgb(255, 255, 0);\">Payment Method: {PaymentMethod}</font></b></div><div><b><font color=\"#000000\" style=\"background-color: rgb(255, 255, 0);\">Transaction ID: {TransactionId}</font></b></div><div><br></div><div>Your updated wallet balance is now {Balance}. This balance can be used to conveniently and securely pay for your next ride.</div><div><br></div><div>As always, we strive to provide you with the best user experience, and your feedback is valuable to us. We look forward to continuing to serve you and making your experience with us even better.</div><div><br></div><div>Thank you once again for choosing&nbsp;<span style=\"font-weight: bolder;\"><font color=\"#000000\" style=\"background-color: rgb(255, 255, 0);\">{AppName}</font></span>. We appreciate your continued support.</div><div><br></div><div><b><font color=\"#000000\" style=\"background-color: rgb(255, 255, 0);\">Best regards,</font></b></div><div><b><font color=\"#000000\" style=\"background-color: rgb(255, 255, 0);\"><br></font></b></div><div><b><font color=\"#000000\" style=\"background-color: rgb(255, 255, 0);\">{AppName}<br><br></font></b></div>', 'false', '2023-08-04 04:02:29', '2024-12-18 15:14:05'),
(3, 'payout_approve_disapprove', 'Payout Request Status -{RequestId}', '<p><span style=\"background-color: rgb(255, 255, 0);\">Dear {UserName},</span></p><p><span style=\"font-size: 1rem;\">I hope this email finds you well. We would like to inform you about the status of your recent payout request with the Request ID {RequestId}.</span><br></p><p><span style=\"font-size: 1rem;\">We are pleased to inform you that your payout request has been {Status}. The requested amount will be processed and transferred to your designated account within short time. Please note that the processing time may vary depending on your financial institution.</span><br></p><p><span style=\"font-size: 1rem; background-color: rgb(255, 255, 0);\">Here are the details of your {Status} payout:</span><br></p><p><span style=\"background-color: rgb(255, 255, 0);\"><span style=\"font-size: 1rem;\">Request ID: {RequestId}<br></span><span style=\"font-size: 1rem;\">Amount: {Amount}</span><span style=\"font-size: 1rem;\"><br></span></span><span style=\"color: rgb(55, 65, 81); font-family: SĂ¶hne, ui-sans-serif, system-ui, -apple-system, &quot;Segoe UI&quot;, Roboto, Ubuntu, Cantarell, &quot;Noto Sans&quot;, sans-serif, &quot;Helvetica Neue&quot;, Arial, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;, &quot;Noto Color Emoji&quot;; white-space-collapse: preserve; background-color: rgb(255, 255, 0);\">Date: {Date}</span></p><p><span style=\"font-size: 1rem;\">Alternatively, in the unlikely event that your payout request has been disapproved, we regret to inform you that the request cannot be fulfilled at this time. The reasons for disapproval may include, but are not limited to, incomplete or incorrect information provided, failure to meet eligibility criteria, or violation of our platforms terms of service.</span><br></p><p><span style=\"font-size: 1rem;\">If you believe there might have been a misunderstanding or you would like to discuss the matter further, kindly get in touch with our support team, and we will be happy to assist you.</span><br></p><p><span style=\"font-size: 1rem;\">We value your partnership with us, and our team is always here to help. We look forward to continued success together.</span><br></p><p><span style=\"font-size: 1rem;\">Thank you for being a part of our community.</span><br></p><p><span style=\"background-color: rgb(255, 255, 0);\"><span style=\"font-size: 1rem;\"><br>Best regards,</span><br></span></p><p><span style=\"background-color: rgb(255, 255, 0);\">{AppName}</span></p>', 'false', '2023-08-04 04:03:43', '2023-08-04 10:49:57'),
(4, 'payout_request', 'Payout Request - {PayoutRequestId}', '<div><font color=\"#374151\" face=\"SĂ¶hne, ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Ubuntu, Cantarell, Noto Sans, sans-serif, Helvetica Neue, Arial, Apple Color Emoji, Segoe UI Emoji, Segoe UI Symbol, Noto Color Emoji\"><span style=\"white-space-collapse: preserve; background-color: rgb(255, 255, 0);\">Hi {AppName},</span></font></div><div><font color=\"#374151\" face=\"SĂ¶hne, ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Ubuntu, Cantarell, Noto Sans, sans-serif, Helvetica Neue, Arial, Apple Color Emoji, Segoe UI Emoji, Segoe UI Symbol, Noto Color Emoji\"><span style=\"white-space-collapse: preserve;\"><br></span></font></div><div><font color=\"#374151\" face=\"SĂ¶hne, ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Ubuntu, Cantarell, Noto Sans, sans-serif, Helvetica Neue, Arial, Apple Color Emoji, Segoe UI Emoji, Segoe UI Symbol, Noto Color Emoji\"><span style=\"white-space-collapse: preserve;\">I hope this email finds you well. I am writing to request a payout for {UserName}&nbsp; account with ID number {UserId}.&nbsp;</span></font></div><div><font color=\"#374151\" face=\"SĂ¶hne, ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Ubuntu, Cantarell, Noto Sans, sans-serif, Helvetica Neue, Arial, Apple Color Emoji, Segoe UI Emoji, Segoe UI Symbol, Noto Color Emoji\"><span style=\"white-space-collapse: preserve;\"><br></span></font></div><div><font color=\"#374151\" face=\"SĂ¶hne, ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Ubuntu, Cantarell, Noto Sans, sans-serif, Helvetica Neue, Arial, Apple Color Emoji, Segoe UI Emoji, Segoe UI Symbol, Noto Color Emoji\"><span style=\"white-space-collapse: preserve;\">Below are the details of my payout request:</span></font></div><div><font color=\"#374151\" face=\"SĂ¶hne, ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Ubuntu, Cantarell, Noto Sans, sans-serif, Helvetica Neue, Arial, Apple Color Emoji, Segoe UI Emoji, Segoe UI Symbol, Noto Color Emoji\"><span style=\"white-space-collapse: preserve;\"><br></span></font></div><div><font color=\"#374151\" face=\"SĂ¶hne, ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Ubuntu, Cantarell, Noto Sans, sans-serif, Helvetica Neue, Arial, Apple Color Emoji, Segoe UI Emoji, Segoe UI Symbol, Noto Color Emoji\"><span style=\"white-space-collapse: preserve; background-color: rgb(255, 255, 0);\">Account ID: {UserId}</span></font></div><div><font color=\"#374151\" face=\"SĂ¶hne, ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Ubuntu, Cantarell, Noto Sans, sans-serif, Helvetica Neue, Arial, Apple Color Emoji, Segoe UI Emoji, Segoe UI Symbol, Noto Color Emoji\"><span style=\"white-space-collapse: preserve; background-color: rgb(255, 255, 0);\">Amount Requested:{Amount}</span></font></div><div><span style=\"white-space-collapse: preserve; color: rgb(55, 65, 81); font-family: SĂ¶hne, ui-sans-serif, system-ui, -apple-system, &quot;Segoe UI&quot;, Roboto, Ubuntu, Cantarell, &quot;Noto Sans&quot;, sans-serif, &quot;Helvetica Neue&quot;, Arial, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;, &quot;Noto Color Emoji&quot;; font-size: 1rem; background-color: rgb(255, 255, 0);\">Payment Account ID: {PayoutRequestId}\r\n</span><div><span style=\"white-space-collapse: preserve; color: rgb(55, 65, 81); font-family: SĂ¶hne, ui-sans-serif, system-ui, -apple-system, &quot;Segoe UI&quot;, Roboto, Ubuntu, Cantarell, &quot;Noto Sans&quot;, sans-serif, &quot;Helvetica Neue&quot;, Arial, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;, &quot;Noto Color Emoji&quot;; font-size: 1rem; background-color: rgb(255, 255, 0);\">Date: {Date}</span><br></div></div><div><span style=\"white-space-collapse: preserve; color: rgb(55, 65, 81); font-family: SĂ¶hne, ui-sans-serif, system-ui, -apple-system, &quot;Segoe UI&quot;, Roboto, Ubuntu, Cantarell, &quot;Noto Sans&quot;, sans-serif, &quot;Helvetica Neue&quot;, Arial, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;, &quot;Noto Color Emoji&quot;; font-size: 1rem; background-color: rgb(255, 255, 0);\"><br></span></div><div><font color=\"#374151\" face=\"SĂ¶hne, ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Ubuntu, Cantarell, Noto Sans, sans-serif, Helvetica Neue, Arial, Apple Color Emoji, Segoe UI Emoji, Segoe UI Symbol, Noto Color Emoji\"><span style=\"white-space-collapse: preserve;\"><br></span></font></div><div><font color=\"#374151\" face=\"SĂ¶hne, ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Ubuntu, Cantarell, Noto Sans, sans-serif, Helvetica Neue, Arial, Apple Color Emoji, Segoe UI Emoji, Segoe UI Symbol, Noto Color Emoji\"><span style=\"white-space-collapse: preserve;\">I would be grateful if you could process my payout request at your earliest convenience. If there are any delays or issues with my request, please inform me as soon as possible so that I can take appropriate action if needed.</span></font></div><div><font color=\"#374151\" face=\"SĂ¶hne, ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Ubuntu, Cantarell, Noto Sans, sans-serif, Helvetica Neue, Arial, Apple Color Emoji, Segoe UI Emoji, Segoe UI Symbol, Noto Color Emoji\"><span style=\"white-space-collapse: preserve;\"><br></span></font></div><div><font color=\"#374151\" face=\"SĂ¶hne, ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Ubuntu, Cantarell, Noto Sans, sans-serif, Helvetica Neue, Arial, Apple Color Emoji, Segoe UI Emoji, Segoe UI Symbol, Noto Color Emoji\"><span style=\"white-space-collapse: preserve;\">Thank you for your attention to this matter. I truly value the partnership we have, and I look forward to your prompt response.</span></font></div><div><font color=\"#374151\" face=\"SĂ¶hne, ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Ubuntu, Cantarell, Noto Sans, sans-serif, Helvetica Neue, Arial, Apple Color Emoji, Segoe UI Emoji, Segoe UI Symbol, Noto Color Emoji\"><span style=\"white-space-collapse: preserve;\"><br></span></font></div><div><font color=\"#374151\" face=\"SĂ¶hne, ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Ubuntu, Cantarell, Noto Sans, sans-serif, Helvetica Neue, Arial, Apple Color Emoji, Segoe UI Emoji, Segoe UI Symbol, Noto Color Emoji\"><span style=\"white-space-collapse: preserve;\">If you require any further information or have any questions, please do not hesitate to reach out to me.</span></font></div><div><font color=\"#374151\" face=\"SĂ¶hne, ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Ubuntu, Cantarell, Noto Sans, sans-serif, Helvetica Neue, Arial, Apple Color Emoji, Segoe UI Emoji, Segoe UI Symbol, Noto Color Emoji\"><span style=\"white-space-collapse: preserve;\"><br></span></font></div><div><font color=\"#374151\" face=\"SĂ¶hne, ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Ubuntu, Cantarell, Noto Sans, sans-serif, Helvetica Neue, Arial, Apple Color Emoji, Segoe UI Emoji, Segoe UI Symbol, Noto Color Emoji\"><span style=\"white-space-collapse: preserve; background-color: rgb(255, 255, 0);\">Best regards,</span></font></div><div><font color=\"#374151\" face=\"SĂ¶hne, ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Ubuntu, Cantarell, Noto Sans, sans-serif, Helvetica Neue, Arial, Apple Color Emoji, Segoe UI Emoji, Segoe UI Symbol, Noto Color Emoji\"><span style=\"white-space-collapse: preserve; background-color: rgb(255, 255, 0);\"><br></span></font></div><div><font color=\"#374151\" face=\"SĂ¶hne, ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Ubuntu, Cantarell, Noto Sans, sans-serif, Helvetica Neue, Arial, Apple Color Emoji, Segoe UI Emoji, Segoe UI Symbol, Noto Color Emoji\"><span style=\"white-space-collapse: preserve; background-color: rgb(255, 255, 0);\">{UserName}</span></font></div><div><font color=\"#374151\" face=\"SĂ¶hne, ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Ubuntu, Cantarell, Noto Sans, sans-serif, Helvetica Neue, Arial, Apple Color Emoji, Segoe UI Emoji, Segoe UI Symbol, Noto Color Emoji\"><span style=\"white-space-collapse: preserve; background-color: rgb(255, 255, 0);\">{UserContactInfo}</span></font></div><div><font color=\"#374151\" face=\"SĂ¶hne, ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Ubuntu, Cantarell, Noto Sans, sans-serif, Helvetica Neue, Arial, Apple Color Emoji, Segoe UI Emoji, Segoe UI Symbol, Noto Color Emoji\"><span style=\"white-space-collapse: preserve; background-color: rgb(255, 255, 0);\">{AppName}</span></font></div>', 'true', '2023-08-04 04:06:28', '2023-08-04 12:12:01'),
(5, 'new_registration', 'New Driver Registration', '<p style=\"margin-bottom: 1rem;\"><span style=\"background-color: rgb(255, 255, 0);\">Hi {AppName},</span></p><p style=\"margin-bottom: 1rem;\"><span style=\"font-size: 1rem;\">I hope this email finds you well. I am writing to inform you about a new user registration on our platform. We are excited to welcome a new member to our community!</span><br></p><p style=\"margin-bottom: 1rem;\"><span style=\"font-size: 1rem;\">Below are the details of the new vendor:</span><br></p><p style=\"margin-bottom: 1rem;\"><span style=\"background-color: rgb(255, 255, 0);\">Account ID: {UserId}<br><span style=\"font-size: 1rem;\">Name: {UserName}<br></span><span style=\"font-size: 1rem;\">Email Address: {UserEmail}<br></span></span><span style=\"background-color: rgb(255, 255, 0); font-size: 1rem;\">Phone Number: {UserPhone}</span><span style=\"background-color: rgb(255, 255, 0); font-size: 1rem;\"><br></span><span style=\"background-color: rgb(255, 255, 0); font-size: 1rem;\">Date of Registration: {Date}</span></p><p style=\"margin-bottom: 1rem;\">As an administrator, you have the privilege to review and verify the new user\'s details to ensure that they comply with our policies and guidelines. Please take a moment to check the provided information and activate the user\'s account if everything appears to be in order. If you have any concerns or need further information, feel free to reach out to the user directly.</p><p style=\"margin-bottom: 1rem;\">We believe that this new addition will enrich our platform and contribute positively to our growing community. By providing them with a warm welcome and support, we can create a positive experience for both the user and our existing members.</p><p style=\"margin-bottom: 1rem;\">Thank you for your continued dedication to maintaining the integrity and security of our platform.</p><p style=\"margin-bottom: 1rem;\"><br></p><p style=\"margin-bottom: 1rem;\"><span style=\"background-color: rgb(255, 255, 0);\">Best regards,</span></p><p style=\"margin-bottom: 1rem;\"><span style=\"background-color: rgb(255, 255, 0);\">{AppName}</span></p>', 'true', '2023-08-04 11:27:24', '2023-08-04 11:37:19'),
(6, 'reset_password', 'Reset Your Password', '<p><font color=\"#000000\" style=\"background-color: rgb(255, 255, 0);\">Dear {UserName},</font></p><p>We are sending this email because you requested a password reset.</p><p>Please use {OTP} code to reset your password</p><p><br></p>ThankYou', 'false', '2023-08-04 14:00:45', '2023-08-04 14:09:48');
