INSERT INTO `terms_and_conditions` (`id`, `terms`, `statut`, `creer`, `modifier`, `updated_at`) VALUES
(1, '<h1 style=\"color: rgb(0, 0, 0); font-family: Times; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Terms and Conditions</h1><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Last updated: June 11, 2025</p><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">This Terms and Conditions describes Our policies and procedures on the collection,\n use and disclosure of Your information when You use the Service and \ntells You about Your privacy rights and how the law protects You.</p><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">We\n use Your Personal data to provide and improve the Service. By using the\n Service, You agree to the collection and use of information in \naccordance with this Privacy Policy. This Privacy Policy has been \ncreated with the help of the<span>&nbsp;</span><a href=\"https://www.termsfeed.com/privacy-policy-generator/\" target=\"_blank\">Privacy Policy Generator</a>.</p><h2 style=\"color: rgb(0, 0, 0); font-family: Times; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Interpretation and Definitions</h2><h3 style=\"color: rgb(0, 0, 0); font-family: Times; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Interpretation</h3><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">The\n words of which the initial letter is capitalized have meanings defined \nunder the following conditions. The following definitions shall have the\n same meaning regardless of whether they appear in singular or in \nplural.</p><h3 style=\"color: rgb(0, 0, 0); font-family: Times; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Definitions</h3><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">For the purposes of this Privacy Policy:</p><ul style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\"><li><p><strong>Account</strong><span>&nbsp;</span>means a unique account created for You to access our Service or parts of our Service.</p></li><li><p><strong>Affiliate</strong><span>&nbsp;</span>means\n an entity that controls, is controlled by or is under common control \nwith a party, where \"control\" means ownership of 50% or more of the \nshares, equity interest or other securities entitled to vote for \nelection of directors or other managing authority.</p></li><li><p><strong>Company</strong><span>&nbsp;</span>(referred to as either \"the Company\", \"We\", \"Us\" or \"Our\" in this Agreement) refers to fastbuss LLC, Barlastone Park.</p></li><li><p><strong>Cookies</strong><span>&nbsp;</span>are\n small files that are placed on Your computer, mobile device or any \nother device by a website, containing the details of Your browsing \nhistory on that website among its many uses.</p></li><li><p><strong>Country</strong><span>&nbsp;</span>refers to: Cameroon</p></li><li><p><strong>Device</strong><span>&nbsp;</span>means any device that can access the Service such as a computer, a cellphone or a digital tablet.</p></li><li><p><strong>Personal Data</strong><span>&nbsp;</span>is any information that relates to an identified or identifiable individual.</p></li><li><p><strong>Service</strong><span>&nbsp;</span>refers to the Website.</p></li><li><p><strong>Service Provider</strong><span>&nbsp;</span>means\n any natural or legal person who processes the data on behalf of the \nCompany. It refers to third-party companies or individuals employed by \nthe Company to facilitate the Service, to provide the Service on behalf \nof the Company, to perform services related to the Service or to assist \nthe Company in analyzing how the Service is used.</p></li><li><p><strong>Third-party Social Media Service</strong><span>&nbsp;</span>refers to any website or any social network website through which a User can log in or create an account to use the Service.</p></li><li><p><strong>Usage Data</strong><span>&nbsp;</span>refers\n to data collected automatically, either generated by the use of the \nService or from the Service infrastructure itself (for example, the \nduration of a page visit).</p></li><li><p><strong>Website</strong><span>&nbsp;</span>refers to fastbuss, accessible from<span>&nbsp;</span><a href=\"https://www.fastbuss.com\" rel=\"external nofollow noopener\" target=\"_blank\">https://www.fastbuss.com</a></p></li><li><p><strong>You</strong><span>&nbsp;</span>means\n the individual accessing or using the Service, or the company, or other\n legal entity on behalf of which such individual is accessing or using \nthe Service, as applicable.</p></li></ul><h2 style=\"color: rgb(0, 0, 0); font-family: Times; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Collecting and Using Your Personal Data</h2><h3 style=\"color: rgb(0, 0, 0); font-family: Times; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Types of Data Collected</h3><h4 style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Personal Data</h4><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">While\n using Our Service, We may ask You to provide Us with certain personally\n identifiable information that can be used to contact or identify You. \nPersonally identifiable information may include, but is not limited to:</p><ul style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\"><li><p>Email address</p></li><li><p>First name and last name</p></li><li><p>Phone number</p></li><li><p>Address, State, Province, ZIP/Postal code, City</p></li><li><p>Usage Data</p></li></ul><h4 style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Usage Data</h4><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Usage Data is collected automatically when using the Service.</p><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Usage\n Data may include information such as Your Device\'s Internet Protocol \naddress (e.g. IP address), browser type, browser version, the pages of \nour Service that You visit, the time and date of Your visit, the time \nspent on those pages, unique device identifiers and other diagnostic \ndata.</p><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">When\n You access the Service by or through a mobile device, We may collect \ncertain information automatically, including, but not limited to, the \ntype of mobile device You use, Your mobile device unique ID, the IP \naddress of Your mobile device, Your mobile operating system, the type of\n mobile Internet browser You use, unique device identifiers and other \ndiagnostic data.</p><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">We\n may also collect information that Your browser sends whenever You visit\n our Service or when You access the Service by or through a mobile \ndevice.</p><h4 style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Information from Third-Party Social Media Services</h4><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">The\n Company allows You to create an account and log in to use the Service \nthrough the following Third-party Social Media Services:</p><ul style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\"><li>Google</li><li>Facebook</li><li>Instagram</li><li>Twitter</li><li>LinkedIn</li></ul><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">If\n You decide to register through or otherwise grant us access to a \nThird-Party Social Media Service, We may collect Personal data that is \nalready associated with Your Third-Party Social Media Service\'s account,\n such as Your name, Your email address, Your activities or Your contact \nlist associated with that account.</p><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">You\n may also have the option of sharing additional information with the \nCompany through Your Third-Party Social Media Service\'s account. If You \nchoose to provide such information and Personal Data, during \nregistration or otherwise, You are giving the Company permission to use,\n share, and store it in a manner consistent with this Privacy Policy.</p><h4 style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Tracking Technologies and Cookies</h4><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">We\n use Cookies and similar tracking technologies to track the activity on \nOur Service and store certain information. Tracking technologies used \nare beacons, tags, and scripts to collect and track information and to \nimprove and analyze Our Service. The technologies We use may include:</p><ul style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\"><li><strong>Cookies or Browser Cookies.</strong><span>&nbsp;</span>A\n cookie is a small file placed on Your Device. You can instruct Your \nbrowser to refuse all Cookies or to indicate when a Cookie is being \nsent. However, if You do not accept Cookies, You may not be able to use \nsome parts of our Service. Unless you have adjusted Your browser setting\n so that it will refuse Cookies, our Service may use Cookies.</li><li><strong>Web Beacons.</strong><span>&nbsp;</span>Certain\n sections of our Service and our emails may contain small electronic \nfiles known as web beacons (also referred to as clear gifs, pixel tags, \nand single-pixel gifs) that permit the Company, for example, to count \nusers who have visited those pages or opened an email and for other \nrelated website statistics (for example, recording the popularity of a \ncertain section and verifying system and server integrity).</li></ul><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Cookies\n can be \"Persistent\" or \"Session\" Cookies. Persistent Cookies remain on \nYour personal computer or mobile device when You go offline, while \nSession Cookies are deleted as soon as You close Your web browser. You \ncan learn more about cookies on<span>&nbsp;</span><a href=\"https://www.termsfeed.com/blog/cookies/#What_Are_Cookies\" target=\"_blank\">TermsFeed website</a><span>&nbsp;</span>article.</p><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">We use both Session and Persistent Cookies for the purposes set out below:</p><ul style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\"><li><p><strong>Necessary / Essential Cookies</strong></p><p>Type: Session Cookies</p><p>Administered by: Us</p><p>Purpose:\n These Cookies are essential to provide You with services available \nthrough the Website and to enable You to use some of its features. They \nhelp to authenticate users and prevent fraudulent use of user accounts. \nWithout these Cookies, the services that You have asked for cannot be \nprovided, and We only use these Cookies to provide You with those \nservices.</p></li><li><p><strong>Cookies Policy / Notice Acceptance Cookies</strong></p><p>Type: Persistent Cookies</p><p>Administered by: Us</p><p>Purpose: These Cookies identify if users have accepted the use of cookies on the Website.</p></li><li><p><strong>Functionality Cookies</strong></p><p>Type: Persistent Cookies</p><p>Administered by: Us</p><p>Purpose:\n These Cookies allow us to remember choices You make when You use the \nWebsite, such as remembering your login details or language preference. \nThe purpose of these Cookies is to provide You with a more personal \nexperience and to avoid You having to re-enter your preferences every \ntime You use the Website.</p></li></ul><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">For\n more information about the cookies we use and your choices regarding \ncookies, please visit our Cookies Policy or the Cookies section of our \nPrivacy Policy.</p><h3 style=\"color: rgb(0, 0, 0); font-family: Times; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Use of Your Personal Data</h3><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">The Company may use Personal Data for the following purposes:</p><ul style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\"><li><p><strong>To provide and maintain our Service</strong>, including to monitor the usage of our Service.</p></li><li><p><strong>To manage Your Account:</strong><span>&nbsp;</span>to\n manage Your registration as a user of the Service. The Personal Data \nYou provide can give You access to different functionalities of the \nService that are available to You as a registered user.</p></li><li><p><strong>For the performance of a contract:</strong><span>&nbsp;</span>the\n development, compliance and undertaking of the purchase contract for \nthe products, items or services You have purchased or of any other \ncontract with Us through the Service.</p></li><li><p><strong>To contact You:</strong><span>&nbsp;</span>To\n contact You by email, telephone calls, SMS, or other equivalent forms \nof electronic communication, such as a mobile application\'s push \nnotifications regarding updates or informative communications related to\n the functionalities, products or contracted services, including the \nsecurity updates, when necessary or reasonable for their implementation.</p></li><li><p><strong>To provide You</strong><span>&nbsp;</span>with\n news, special offers and general information about other goods, \nservices and events which we offer that are similar to those that you \nhave already purchased or enquired about unless You have opted not to \nreceive such information.</p></li><li><p><strong>To manage Your requests:</strong><span>&nbsp;</span>To attend and manage Your requests to Us.</p></li><li><p><strong>For business transfers:</strong><span>&nbsp;</span>We\n may use Your information to evaluate or conduct a merger, divestiture, \nrestructuring, reorganization, dissolution, or other sale or transfer of\n some or all of Our assets, whether as a going concern or as part of \nbankruptcy, liquidation, or similar proceeding, in which Personal Data \nheld by Us about our Service users is among the assets transferred.</p></li><li><p><strong>For other purposes</strong>:\n We may use Your information for other purposes, such as data analysis, \nidentifying usage trends, determining the effectiveness of our \npromotional campaigns and to evaluate and improve our Service, products,\n services, marketing and your experience.</p></li></ul><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">We may share Your personal information in the following situations:</p><ul style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\"><li><strong>With Service Providers:</strong><span>&nbsp;</span>We may share Your personal information with Service Providers to monitor and analyze the use of our Service, to contact You.</li><li><strong>For business transfers:</strong><span>&nbsp;</span>We\n may share or transfer Your personal information in connection with, or \nduring negotiations of, any merger, sale of Company assets, financing, \nor acquisition of all or a portion of Our business to another company.</li><li><strong>With Affiliates:</strong><span>&nbsp;</span>We\n may share Your information with Our affiliates, in which case we will \nrequire those affiliates to honor this Privacy Policy. Affiliates \ninclude Our parent company and any other subsidiaries, joint venture \npartners or other companies that We control or that are under common \ncontrol with Us.</li><li><strong>With business partners:</strong><span>&nbsp;</span>We may share Your information with Our business partners to offer You certain products, services or promotions.</li><li><strong>With other users:</strong><span>&nbsp;</span>when\n You share personal information or otherwise interact in the public \nareas with other users, such information may be viewed by all users and \nmay be publicly distributed outside. If You interact with other users or\n register through a Third-Party Social Media Service, Your contacts on \nthe Third-Party Social Media Service may see Your name, profile, \npictures and description of Your activity. Similarly, other users will \nbe able to view descriptions of Your activity, communicate with You and \nview Your profile.</li><li><strong>With Your consent</strong>: We may disclose Your personal information for any other purpose with Your consent.</li></ul><h3 style=\"color: rgb(0, 0, 0); font-family: Times; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Retention of Your Personal Data</h3><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">The\n Company will retain Your Personal Data only for as long as is necessary\n for the purposes set out in this Privacy Policy. We will retain and use\n Your Personal Data to the extent necessary to comply with our legal \nobligations (for example, if we are required to retain your data to \ncomply with applicable laws), resolve disputes, and enforce our legal \nagreements and policies.</p><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">The\n Company will also retain Usage Data for internal analysis purposes. \nUsage Data is generally retained for a shorter period of time, except \nwhen this data is used to strengthen the security or to improve the \nfunctionality of Our Service, or We are legally obligated to retain this\n data for longer time periods.</p><h3 style=\"color: rgb(0, 0, 0); font-family: Times; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Transfer of Your Personal Data</h3><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Your\n information, including Personal Data, is processed at the Company\'s \noperating offices and in any other places where the parties involved in \nthe processing are located. It means that this information may be \ntransferred to â€” and maintained on â€” computers located outside of Your \nstate, province, country or other governmental jurisdiction where the \ndata protection laws may differ than those from Your jurisdiction.</p><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Your consent to this Privacy Policy followed by Your submission of such information represents Your agreement to that transfer.</p><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">The\n Company will take all steps reasonably necessary to ensure that Your \ndata is treated securely and in accordance with this Privacy Policy and \nno transfer of Your Personal Data will take place to an organization or a\n country unless there are adequate controls in place including the \nsecurity of Your data and other personal information.</p><h3 style=\"color: rgb(0, 0, 0); font-family: Times; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Delete Your Personal Data</h3><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">You have the right to delete or request that We assist in deleting the Personal Data that We have collected about You.</p><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Our Service may give You the ability to delete certain information about You from within the Service.</p><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">You\n may update, amend, or delete Your information at any time by signing in\n to Your Account, if you have one, and visiting the account settings \nsection that allows you to manage Your personal information. You may \nalso contact Us to request access to, correct, or delete any personal \ninformation that You have provided to Us.</p><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Please note, however, that We may need to retain certain information when we have a legal obligation or lawful basis to do so.</p><h3 style=\"color: rgb(0, 0, 0); font-family: Times; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Disclosure of Your Personal Data</h3><h4 style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Business Transactions</h4><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">If\n the Company is involved in a merger, acquisition or asset sale, Your \nPersonal Data may be transferred. We will provide notice before Your \nPersonal Data is transferred and becomes subject to a different Privacy \nPolicy.</p><h4 style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Law enforcement</h4><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Under\n certain circumstances, the Company may be required to disclose Your \nPersonal Data if required to do so by law or in response to valid \nrequests by public authorities (e.g. a court or a government agency).</p><h4 style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Other legal requirements</h4><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">The Company may disclose Your Personal Data in the good faith belief that such action is necessary to:</p><ul style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\"><li>Comply with a legal obligation</li><li>Protect and defend the rights or property of the Company</li><li>Prevent or investigate possible wrongdoing in connection with the Service</li><li>Protect the personal safety of Users of the Service or the public</li><li>Protect against legal liability</li></ul><h3 style=\"color: rgb(0, 0, 0); font-family: Times; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Security of Your Personal Data</h3><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">The\n security of Your Personal Data is important to Us, but remember that no\n method of transmission over the Internet, or method of electronic \nstorage is 100% secure. While We strive to use commercially acceptable \nmeans to protect Your Personal Data, We cannot guarantee its absolute \nsecurity.</p><h2 style=\"color: rgb(0, 0, 0); font-family: Times; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Children\'s Privacy</h2><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Our\n Service does not address anyone under the age of 13. We do not \nknowingly collect personally identifiable information from anyone under \nthe age of 13. If You are a parent or guardian and You are aware that \nYour child has provided Us with Personal Data, please contact Us. If We \nbecome aware that We have collected Personal Data from anyone under the \nage of 13 without verification of parental consent, We take steps to \nremove that information from Our servers.</p><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">If\n We need to rely on consent as a legal basis for processing Your \ninformation and Your country requires consent from a parent, We may \nrequire Your parent\'s consent before We collect and use that \ninformation.</p><h2 style=\"color: rgb(0, 0, 0); font-family: Times; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Links to Other Websites</h2><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Our\n Service may contain links to other websites that are not operated by \nUs. If You click on a third party link, You will be directed to that \nthird party\'s site. We strongly advise You to review the Privacy Policy \nof every site You visit.</p><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">We\n have no control over and assume no responsibility for the content, \nprivacy policies or practices of any third party sites or services.</p><h2 style=\"color: rgb(0, 0, 0); font-family: Times; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Changes to this Privacy Policy</h2><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">We\n may update Our Privacy Policy from time to time. We will notify You of \nany changes by posting the new Privacy Policy on this page.</p><p style=\"color: rgb(0, 0, 0); font-family: Times; font-size: medium; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spac